    int M, T, S;
    long long N;
    cin &gt;&gt; M &gt;&gt; T &gt;&gt; S &gt;&gt; N;
    vector&lt;vector&lt;int&gt;&gt; nextToken(M+1, vector&lt;int&gt;(T+1));
    vector&lt;vector&lt;int&gt;&gt; nextMachine(M+1, vector&lt;int&gt;(T+1));
    for (int m = 1; m &lt;= M; m++){
        for (int t = 1; t &lt;= T; t++){
            cin &gt;&gt; nextToken[m][t] &gt;&gt; nextMachine[m][t];
        }
    }
    int totalStates = M * T;
    // Encode state as (machine-1)*T + (token-1)
    auto encode = [&amp;](int machine, int token) {
        return (machine - 1) * T + (token - 1);
    };
    // Decode to retrieve machine number
    auto decodeMachine = [&amp;](int state) {
        return state / T + 1;
    };

    // dp[0][state]: next state after one transition
    vector&lt;int&gt; dp0(totalStates);
    for (int machine = 1; machine &lt;= M; machine++){
        for (int token = 1; token &lt;= T; token++){
            int cur = encode(machine, token);
            int nxt_machine = nextMachine[machine][token];
            int nxt_token = nextToken[machine][token];
            int nxt_state = encode(nxt_machine, nxt_token);
            dp0[cur] = nxt_state;
        }
    }

    // Build the doubling table
    int maxK = 0;
    while ((1LL &lt;&lt; maxK) &lt;= N) maxK++;
    vector&lt;vector&lt;int&gt;&gt; dp(maxK, vector&lt;int&gt;(totalStates));
    dp[0] = dp0;
    for (int k = 1; k &lt; maxK; k++){
        for (int i = 0; i &lt; totalStates; i++){
            dp[k][i] = dp[k-1][ dp[k-1][i] ];
        }
    }

    int cur = encode(S, 1);
    long long steps = N - 1; // Already at initial state
    for (int k = 0; k &lt; maxK; k++){
        if (steps &amp; (1LL &lt;&lt; k)){
            cur = dp[k][cur];
        }
    }
    cout &lt;&lt; decodeMachine(cur) &lt;&lt; "\n";
    return 0;
}
