    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    M = int(next(it))
    T = int(next(it))
    S = int(next(it))
    N = int(next(it))

    nextToken = [[0]*(T+1) for _ in range(M+1)]
    nextMachine = [[0]*(T+1) for _ in range(M+1)]
    for m in range(1, M+1):
        for t in range(1, T+1):
            nextToken[m][t] = int(next(it))
            nextMachine[m][t] = int(next(it))

    def encode(machine, token):
        return (machine - 1) * T + (token - 1)
    def decode_machine(state):
        return state // T + 1

    total_states = M * T
    dp0 = [0] * total_states
    for machine in range(1, M+1):
        for token in range(1, T+1):
            cur = encode(machine, token)
            nxt_machine = nextMachine[machine][token]
            nxt_token = nextToken[machine][token]
            nxt_state = encode(nxt_machine, nxt_token)
            dp0[cur] = nxt_state

    # Build doubling table
    maxK = 0
    while (1 &lt;&lt; maxK) &lt;= N:
        maxK += 1
    dp = [dp0]
    for k in range(1, maxK):
        prev = dp[k-1]
        curr = [0] * total_states
        for i in range(total_states):
            curr[i] = prev[prev[i]]
        dp.append(curr)

    cur = encode(S, 1)
    steps = N - 1  # Already at initial state
    bit = 0
    while steps:
        if steps &amp; 1:
            cur = dp[bit][cur]
        steps //= 2
        bit += 1

    sys.stdout.write(str(decode_machine(cur)))

if __name__ == '__main__':
    main()
